  function loadState(){
    try{
      const raw = localStorage.getItem(STORAGE_KEY);
      if(!raw) return createDefaultState();
      const parsed = JSON.parse(raw);
      return mergeWithDefaults(parsed);
    }catch(error){
      console.error(error);
      return createDefaultState();
    }
  }

  function mergeWithDefaults(input){
    const base = createDefaultState();
    if(!input || typeof input !== 'object') return base;

    base.meta = { ...base.meta, ...(input.meta || {}) };
    base.auth = { ...base.auth, ...(input.auth || {}) };
    base.brand = { ...base.brand, ...(input.brand || {}) };
    base.theme = { ...base.theme, ...(input.theme || {}) };
    base.theme.custom = { ...base.theme.custom, ...((input.theme || {}).custom || {}) };
    base.interface = { ...base.interface, ...(input.interface || {}) };
    base.security = { ...base.security, ...(input.security || {}) };
    base.labels = { ...base.labels, ...(input.labels || {}) };
    base.prayers = { ...base.prayers, ...(input.prayers || {}) };
    base.prayers.times = { ...base.prayers.times, ...((input.prayers || {}).times || {}) };
    base.prayers.alarms = { ...base.prayers.alarms, ...((input.prayers || {}).alarms || {}) };
    base.quran = { ...base.quran, ...(input.quran || {}) };
    base.mafatih = { ...base.mafatih, ...(input.mafatih || {}) };
    base.viewer = { ...base.viewer, ...(input.viewer || {}) };

    base.sections = deepClone(base.sections);
    if(input.sections && typeof input.sections === 'object'){
      Object.keys(base.sections).forEach(id => {
        base.sections[id] = { ...base.sections[id], ...(input.sections[id] || {}) };
      });
    }

    [
      'customPages','devotions','tasks','appointments','fixedAppointments','sports','meals','goals','notes','vault','alarms'
    ].forEach(key => {
      if(Array.isArray(input[key])) base[key] = input[key];
    });

    if(typeof input.waterCount === 'number') base.waterCount = clamp(input.waterCount, 0, 12);
    return base;
  }

  function normalizeState(){
    state = mergeWithDefaults(state);
    const legacyPresetMap = { 'local-audio': 'local-audio' };
    if(legacyPresetMap[state.prayers.preset]) state.prayers.preset = legacyPresetMap[state.prayers.preset];
    if(!state.prayers.backupAdhanUrl) state.prayers.backupAdhanUrl = DEFAULT_ADHAN_URL;
    if(state.prayers.preset === 'local-audio' && (state.prayers.adhanDisplayName || '').includes('—')) state.prayers.adhanDisplayName = 'أذان محلي';
    if(!state.prayers.adhanDisplayName) state.prayers.adhanDisplayName = defaultAdhanNameForPreset(state.prayers.preset);
    runtime.view = (runtime.view === 'settings' || visibleEntries().some(item => item.id === runtime.view)) ? runtime.view : 'home';
    runtime.viewerUrl = state.viewer.url || '';
    runtime.quranQuery = state.quran.query || '';
    runtime.mafatihQuery = state.mafatih.query || '';
    runtime.calcExpression = runtime.calcExpression || '';
    runtime.calcDisplay = runtime.calcExpression || '0';
    document.documentElement.style.setProperty('--density', String(state.theme.density || 1));
    document.title = state.brand.appName || 'ترتيب';
    if(ui.favicon) ui.favicon.href = state.brand.icon || DEFAULT_ICON;
    if(ui.globalSearch) ui.globalSearch.placeholder = state.labels.searchPlaceholder || 'بحث';
  }

  function persist(showToastMessage = true){
    state.meta.lastSavedAt = new Date().toISOString();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    normalizeState();
    applyTheme();
    renderBrand();
    renderNav();
    renderTopbarBits();
    renderCurrentView();
    if(showToastMessage) toast('تم الحفظ');
  }

  function deepClone(obj){
    return JSON.parse(JSON.stringify(obj));
  }

  function uid(prefix = 'id'){
    return `${prefix}_${Math.random().toString(36).slice(2, 10)}`;
  }

  function clamp(n, min, max){
    return Math.max(min, Math.min(max, Number(n)));
  }

  function futureDateTime(addDays, hour, minute){
    const d = new Date();
    d.setDate(d.getDate() + addDays);
    d.setHours(hour, minute, 0, 0);
    return d.toISOString().slice(0,16);
  }

  function escapeHtml(value = ''){
    return String(value)
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;')
      .replaceAll("'", '&#39;');
  }

  function hasPin(){
    return Boolean(state.auth.pinHash);
  }

  function defaultAdhanNameForPreset(preset){
    return {
      'local-audio': 'أذان محلي',
      'default-audio': 'الأذان الاحتياطي',
      'custom-url': 'أذان بالرابط',
      'custom-upload': 'الأذان المرفوع'
    }[preset] || 'الأذان';
  }

  function getAdhanDisplayName(){
    return (state.prayers.adhanDisplayName || defaultAdhanNameForPreset(state.prayers.preset)).trim() || 'الأذان';
  }

  function registerSecretTap(){
    if(!sessionStorage.getItem(SESSION_KEY)) return false;
    const now = Date.now();
    if(!runtime.secretTap || now - runtime.secretTap.last > 2200){
      runtime.secretTap = { count: 0, last: now };
    }
    runtime.secretTap.count += 1;
    runtime.secretTap.last = now;
    const needed = clamp(Number(state.security.settingsTapCount || 5), 3, 10);
    if(runtime.secretTap.count >= needed){
      runtime.secretTap = { count: 0, last: 0 };
      openView('settings');
      toast('تم فتح الإعدادات');
      return true;
    }
    return false;
  }

  function showAdhanUi(label){
    if(ui.audioDockTitle) ui.audioDockTitle.textContent = label || 'الأذان';
    if(ui.audioDock) ui.audioDock.classList.remove('hidden');
  }

  function stopAdhan(showMessage = true){
    runtime.activeAdhanMode = '';
    try{
      if(ui.adhanAudio){
        ui.adhanAudio.pause();
        ui.adhanAudio.currentTime = 0;
        ui.adhanAudio.removeAttribute('src');
        ui.adhanAudio.load();
      }
    }catch(error){
      console.error(error);
    }
    if(ui.adhanEmbedHost){
      ui.adhanEmbedHost.innerHTML = '';
      ui.adhanEmbedHost.classList.add('hidden');
    }
    if(ui.audioDock) ui.audioDock.classList.add('hidden');
    if(showMessage) toast('تم إيقاف الأذان');
  }

  async function hashPin(pin){
    if(window.crypto && crypto.subtle){
      const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(pin));
      return Array.from(new Uint8Array(digest)).map(b => b.toString(16).padStart(2,'0')).join('');
    }
    return btoa(pin);
  }


